//
import { Registry } from '../../core/zc-registry';
import { d3_merge } from '../../core/d3-constants';
import { each, arrayIncludes, pick, defined, objectValues, isArray } from '../../utils/zcutils';
import { convertOperatorToProperty } from '../evaluators/mark-config-evaluator';
import { getDashArray, getLineCap } from '../../utils/dashstyles';
import { customMarkMap } from './custom-mark/custom-mark-map';
import { NULL } from '../../core/zc-constants';
import { isExpressionType } from '../parser/parser-helpers';
import { collectReactiveDependencies } from '../../parser/parser-reactive-flow';

function parseMarkConfig(mark, config, obj, morph, parent) {
    config = convertOperatorToProperty.call(obj, config);

    if (!customMarkMap[mark]) {
        each(config, (value, prop) => {
            collectReactiveDependencies(prop, value, config, obj, parent);
        })
        
        return { ...config, ...morpheConfig(config) };
    }

    let parsed = customMarkMap[mark](config, obj),
        o = {},
        parsedConfig = {},
        keys = Object.keys(parsed.depends),
        _delete = d3_merge(objectValues(parsed.depends)).filter(_ => !arrayIncludes(keys, _));

        each(config, (value, prop) => {
            if (!arrayIncludes(_delete, prop)) {
                o[prop] = value;
            }
            collectReactiveDependencies(prop, value, config, obj, parent);
        })

    // Check for atleast one config or shorthand config
    each(parsed.config, (value, prop) => {
        if (defined(config[prop]) || parsed.depends[prop].some(_ => defined(config[_]))) {
            parsedConfig[prop] = value;
        }
    });

    return morph ? { ...o, ...parsedConfig } : { ...o, ...parsedConfig, ...morpheConfig(config) };
}

function morpheConfig(config) {
    let { strokeWidth, lineCap, dashStyle, tooltip: title } = config;

    // Dash style
    strokeWidth = pick(strokeWidth, 1);
    lineCap = getLineCap(lineCap, dashStyle);
    dashStyle = isExpressionType(dashStyle) ? dashStyle : getDashArray(dashStyle, strokeWidth);
    title = function () {
        return config.tooltip ? this.textContent : NULL;
    };

    return { strokeWidth, lineCap, dashStyle, title };
}

export var config_CSS_value_converter = {
    dashStyle: (config, value)=>{
        let strokeWidth = pick(config.strokeWidth, 1);
        return getDashArray(value, strokeWidth);
    }
}

export { parseMarkConfig };
Registry.setComponent('markUtils.customMark', parseMarkConfig);
